        z.height = 1 + max(self.get_height(z.left), self.get_height(z.right))
        y.height = 1 + max(self.get_height(y.left), self.get_height(y.right))
        return y

    def right_rotate(self, z):
        y = z.left
        T3 = y.right
        y.right = z
        z.left = T3
        z.height = 1 + max(self.get_height(z.left), self.get_height(z.right))
        y.height = 1 + max(self.get_height(y.left), self.get_height(y.right))
        return y

    def get_height(self, root):
        if not root:
            return 0
        return root.height

    def get_balance(self, root):
        if not root:
            return 0
        return self.get_height(root.left) - self.get_height(root.right)


La gestione del bilanciamento e cruciale: il metodo di inserimento restituisce la nuova radice del sottoalbero dopo l'eventuale rotazione. Questo garantisce che l'altezza dell'albero rimanga O(log n), mantenendo le prestazioni ottimali per future operazioni di ricerca o inserimento.
